import { Component, ElementRef, Input, OnInit, Renderer2 } from '@angular/core';

type DirectionType = 'horizontal' | 'vertical';

@Component({
  selector: 'app-two-cols-layout',
  templateUrl: './two-cols-layout.component.html',
  styleUrls: ['./two-cols-layout.component.scss']
})
export class TwoColsLayoutComponent implements OnInit {
  @Input() set direction(value: DirectionType) {
    const elementRef = this.elementRef;

    this._direction = value;
    if (elementRef) {
      if (value === 'horizontal') {
        this.renderer.setStyle(elementRef.nativeElement, 'flex-flow', 'row nowrap');
      } else {
        this.renderer.setStyle(elementRef.nativeElement, 'flex-flow', 'column nowrap');
      }
    }
  }

  get direction(): DirectionType {
    return this._direction;
  }

  private _direction: DirectionType = 'horizontal';

  constructor(
    private elementRef: ElementRef<HTMLElement>,
    private renderer: Renderer2
  ) { }

  ngOnInit(): void {
    if (this.direction === 'horizontal') {
      this.renderer.setStyle(this.elementRef.nativeElement, 'flex-flow', 'row nowrap');
    } else {
      this.renderer.setStyle(this.elementRef.nativeElement, 'flex-flow', 'column nowrap');
    }
  }

}
