import {
  AfterViewInit,
  Component,
  ElementRef,
  OnDestroy,
  OnInit,
  Renderer2,
} from '@angular/core';
import { PercentPipe } from '@angular/common';
import { Subscription } from 'rxjs';
import * as d3 from 'd3';

import { SunburstChartOptions } from '../chart-options';
import { ISunburstData } from '../chart-data';
import { ChartBase } from '../chart-base';
import { EventService } from 'app/shared/services/event.service';

@Component({
  selector: 'app-sunburst-chart',
  template: '',
  styleUrls: ['./sunburst-chart.component.scss'],
})
export class SunburstChartComponent
  extends ChartBase
  implements OnInit, AfterViewInit, OnDestroy {

  private svg: d3.Selection<SVGSVGElement, undefined, null, undefined>;

  protected _options = new SunburstChartOptions();
  protected subscription = new Subscription();

  constructor(
    private renderer: Renderer2,
    private percentPipe: PercentPipe,
    protected elementRef: ElementRef<HTMLElement>,
    protected eventService: EventService,
  ) {
    super(elementRef, eventService);
  }

  ngOnInit(): void {
  }

  ngAfterViewInit(): void {
    super.ngAfterViewInit();

    setTimeout(() => {
      this.resetDimension();
      this.draw();
    });
  }

  draw(): void {
    let data = this.data ? this.data[0] : null;

    if (!data) {
      return;
    }
    data = data as ISunburstData;
    if (this.options.series) {
      this.color = d3.scaleOrdinal(
        this.options.series.map((item) => {
          return item.color;
        })
      );
    } else {
      this.color = d3.scaleOrdinal(
        d3.quantize(d3.interpolateRainbow, data ? data.children.length + 1 : 1)
      );
    }

    const width = this.width;
    const height = this.height;
    const radius = Math.min(width, height) / 2;

    const arc = d3
      .arc()
      .startAngle((d) => d.x0)
      .endAngle((d) => d.x1)
      .padAngle((d) => Math.min((d.x1 - d.x0) / 2, 0.005))
      .padRadius(radius / 2)
      .innerRadius((d) => d.y0)
      .outerRadius((d) => d.y1 - 1);

    const root = d3.partition().size([2 * Math.PI, radius])(
      d3.hierarchy(data)
        .sum((d) => d.children && d.children.length ? 0 : d.value)
        .sort((a, b) => b.value - a.value),
      );

    const svg = d3
      .create('svg')
      .attr('viewBox', [-width / 2, -height / 2, width, height]);
    const svgElement = svg.node();
    const path = svg
      .append('g')
      .selectAll('path')
      .data(
        root.descendants().filter((d) => {
          // Don't draw the root node, and for efficiency, filter out nodes that would be too small to see
          return d.depth && d.x1 - d.x0 > 0.001;
        }),
      )
      .join('path')
      .attr('fill', (d) => this.color(d.data.id))
      .attr('d', arc);
    const label = svg
      .append('text')
      .attr('text-anchor', 'middle')
      .attr('fill', '#888');

    svgElement.value = { sequence: [], percentage: 0.0 };
    this.svg = svg;
    this.setLabel(label, data);

    svg
      .append('g')
      .attr('fill-opacity', 0.6)
      .on('mouseleave', () => {
        path.attr('fill-opacity', 0.6);
        this.setLabel(label, this.data ? this.data[0] as ISunburstData : null);
        // Update the value of this view
        svgElement.value = { sequence: [], percentage: 0.0 };
        svgElement.dispatchEvent(new CustomEvent('input'));
      })
      .selectAll('path')
      .data(root.descendants().filter((d) => d.depth))
      .join('path')
      .attr('fill', (d) => {
        while (d.depth > 1) d = d.parent;
        return this.color(d.data.id);
      })
      .attr('d', arc)
      .on('mouseenter', (event, d) => {
        // Get the ancestors of the current segment, minus the root
        const sequence = d.ancestors().reverse().slice(1);
        // Highlight the ancestors
        path.attr('fill-opacity', (node) =>
          sequence.indexOf(node) >= 0 ? 1.0 : 0.3,
        );
        const percentage = this.percentPipe.transform(d.value / root.value, '0.0-2');
        this.setLabel(label, d);
        // Update the value of this view with the currently hovered sequence and percentage
        svgElement.value = { sequence, percentage };
        svgElement.dispatchEvent(new CustomEvent('input'));
      })
      .append('title')
      .text(
        (d) =>
          `${d
            .ancestors()
            .map((d) => d.data.name)
            .reverse()
            .join('/')}\n${this.percentPipe.transform(d.value / root.value, '0.0-2')}`,
      );

    svg
      .append('g')
      .attr('pointer-events', 'none')
      .attr('text-anchor', 'middle')
      .attr('font-size', 10)
      .attr('font-family', 'sans-serif')
      .selectAll('text')
      .data(
        root
          .descendants()
          .filter((d) => d.depth && ((d.y0 + d.y1) / 2) * (d.x1 - d.x0) > 10),
      )
      .join('text')
      .attr('transform', function (d) {
        const x = (((d.x0 + d.x1) / 2) * 180) / Math.PI;
        const y = (d.y0 + d.y1) / 2;
        return `rotate(${
          x - 90
        }) translate(${y},0) rotate(${x < 180 ? 0 : 180})`;
      })
      .attr('dy', '0.35em')
      .text((d) => d.data.name);

    this.renderer.appendChild(this.elementRef.nativeElement, svg.node());
  }

  clear(): void {
    if (this.svg) {
      this.renderer.removeChild(this.elementRef.nativeElement, this.svg.node());
      this.svg = undefined;
    }
  }

  whenViewportResize(): void {

  }

  private setLabel(label: d3.Selection, data: ISunburstData): void {
    let name: string = '';
    let value: number = 0;

    if (data) {
      if (data.name) {
        name = data.name;
      } else if (data.data) {
        name = data.data.name;
      }
      if (typeof data.value === 'number') {
        value = data.value;
      }
    }
    label.selectAll('.percentage').remove();

    label
      .append('tspan')
      .attr('class', 'percentage')
      .attr('x', 0)
      .attr('y', 0)
      .attr('dy', '-0.1em')
      .attr('font-size', '1em')
      .text(name);
    label
      .append('tspan')
      .attr('class', 'percentage')
      .attr('x', 0)
      .attr('y', 0)
      .attr('dy', '1.1em')
      .attr('font-size', '1em')
        .text(this.getFormattedValue(value));
  }
}
