import {
  AfterViewInit,
  Component,
  ElementRef,
  OnInit,
  Renderer2,
} from '@angular/core';
import { Subscription } from 'rxjs';
import * as d3 from 'd3';

import { BarChartOptions, BAR_LAYOUT_TYPE } from '../chart-options';
import { ChartBase } from '../chart-base';
import { EventService } from 'app/shared/services/event.service';

@Component({
  selector: 'app-bar-chart',
  template: '',
  styleUrls: ['./bar-chart.component.scss'],
})
export class BarChartComponent
  extends ChartBase
  implements OnInit, AfterViewInit {
  private svg: d3.Selection<SVGSVGElement, undefined, null, undefined>;
  private bars: d3.Selection<
    d3.BaseType,
    unknown,
    Element | d3.EnterElement | Document | Window | SVGGElement,
    any
  >;
  private line;
  private x: d3.ScaleBand<number | string>;
  private xAxis;
  private y: d3.ScaleLinear<number, number, never>;
  private yAxis;
  private yGridline;


  private yMin: number;
  private yGroupedMax: number;
  private yStackedMax: number;

  protected _options = new BarChartOptions();
  protected color: d3.ScaleSequential;
  protected subscription = new Subscription();

  constructor(
    private renderer: Renderer2,
    protected elementRef: ElementRef<HTMLElement>,
    protected eventService: EventService
  ) {
    super(elementRef, eventService);
    this.svg = d3.create('svg');
    this.x = d3.scaleBand();
    this.y = d3.scaleLinear().clamp(true);
    this.color = d3.scaleSequential(d3.interpolateBlues);
  }

  ngOnInit(): void {
  }

  ngAfterViewInit(): void {
    super.ngAfterViewInit();

    setTimeout(() => {
      this.resetDimension();
      this.draw();
    });
  }

  update() {
    if ((this.options as BarChartOptions).layout === 'stacked') {
      this.transitionStacked();
    } else {
      this.transitionGrouped();
    }
  }

  transitionGrouped(): void {
    const delayValue = this.options.delay;
    const numOfSeries = this.getNumOfSeries();
    const bandWidth = this.getBandWidth();

    this.y.domain([0, this.yGroupedMax]).nice();
    this.svg.select('g.y-axis').call(this.yAxis);
    this.svg.select('g.y-gridline').call(this.yGridline);

    this.bars
      .transition()
      .duration(500)
      .delay((d, i) => i * delayValue)
      .attr('x', (d) => {
        return this.x(d.key) + (bandWidth / numOfSeries) * d[d.length - 1];
      })
      .attr('width', bandWidth / numOfSeries)
      .transition()
      .attr('y', (d) => {
        return this.y(Math.max(0, d[1] - d[0]));
      })
      .attr('height', (d) => this.y(0) - this.y(Math.max(0, d[1] - d[0])));

    this.line.attr('d', '')
  }

  transitionStacked(): void {
    const delayValue = this.options.delay;
    const bandWidth = this.getBandWidth();

    this.y.domain([this.yMin, this.yStackedMax]).nice();
    this.svg.select('g.y-axis').call(this.yAxis);
    this.svg.select('g.y-gridline').call(this.yGridline);

    // this.bars.each((d, i, bar) => {
    //   this.svg.node().appendChild(bar[0].parentElement.parentElement);
    // });
    this.bars
      .transition()
      .duration(500)
      .delay((d, i) => i * delayValue)
      .attr('y', (d) => {
        return this.y(d[1]);
      })
      .attr('height', (d) => {
        return this.y(d[0]) - this.y(d[1]);
      })
      .transition()
      .attr('x', (d) => {
        return this.x(d.key);
      })
      .attr('width', bandWidth);
  }

  draw(): void {
    const data = this.data as Array<Array<number | Date>>;

    if (!data || !data.length) {
      return;
    }
    const width = this.width;
    const height = this.height;
    const margin = this.options.margin;

    const dataLength = this.data.length;
    // number of series
    const n = this.getNumOfSeries();
    // const xDomain = [data[0][0], data[dataLength - 1][0]];
    const xDomain = data.map(item => (item[0] as Date).toISOString());
    const seriesDatas = d3
      .stack()
      .keys(d3.range(1, n + 1))(data) // d3.transpose(data) stacked seriesDatas
      .map((d, i) => d.map((item) => {
        item.key = (item.data[0] as Date).toISOString();
        item[item.length] = i;
        return item;
      }));
    const ticksInterval = Math.ceil(dataLength / (width / 76));
    const xSizeRange = this.getXSizeRange();
    const ySizeRange = this.getYSizeRange();

    this.yMin = d3.min(seriesDatas, (y) => d3.min(y, (d) => d[0]));
    this.yMin = Math.floor(this.yMin);
    this.yGroupedMax = d3.max(seriesDatas, (y) => d3.max(y, (d) => d[1] - d[0]));;
    this.yGroupedMax = Math.ceil(this.yGroupedMax);
    this.yStackedMax = d3.max(seriesDatas, (y) => d3.max(y, (d) => d[1]));
    this.yStackedMax = Math.ceil(this.yStackedMax);

    this.x.domain(xDomain).rangeRound(xSizeRange).padding(Math.max(0.38, 1 / Math.max(1, dataLength) - 0.1));
    this.y.domain([this.yMin, this.yStackedMax]).nice().rangeRound(ySizeRange);
    this.color.domain([-0.5 * n, 1.5 * n]);

    this.xAxis = (g) => {
      g.attr('transform', `translate(0,${height - margin.bottom})`)
        .call(
          d3
            .axisBottom(this.x)
            .ticks(width / 76, 's')
            .tickSizeOuter(0)
            .tickFormat((d, i) => {
              return i % ticksInterval === 0 ? this.getFormattedXValue(d) : '';
            })
        );
    };
    this.yAxis = (g) => {
      g
        .attr('transform', `translate(${margin.left},0)`)
        .call(
          d3.axisLeft(this.y)
            .tickFormat((d) => {
              return this.getFormattedYValue(d);
            })
        )
        .call((g) => {
          g.selectAll('.tick line').remove();
        })
        .call((g) => {
          g.select('.domain').remove()
        });
    };
    this.yGridline = (g) => {
      g
        .attr('transform', `translate(${margin.left},0)`)
        .call(
          d3.axisLeft(this.y)
            .tickSize(0)
            .tickFormat('')
        )
        .call((g) => {
          g.selectAll('.tick line')
            .style('stroke-dasharray', (d) => {
              return d === 0 ? null : '3 3';
            })
            .attr('x2', width - margin.left - margin.right)
            .attr('stroke-opacity', (d) => {
              return d === 0 ? 0.5 : 0.2;
            });
        })
        .call((g) => {
          g.select('.domain').remove()
        });
    };
    const curve = d3.line()
      .curve(d3.curveMonotoneX )
      .x((d, i) => {
        return this.x(d.key);
      })
      .y((d) => {
        return this.y(d[1]);
      });

    const svg = this.svg;
    const bandWidth = this.getBandWidth();

    svg.attr('viewBox', [0, 0, width, height]);
    svg.append('clipPath')
      .attr('id', 'rect-clip')
      .append('rect')
      .attr('x', margin.left)
      .attr('y', 0)
      .attr('width', xSizeRange[1] - xSizeRange[0])
      .attr('height', height);
    svg.append('g')
      .attr('class', 'x-axis')
      .attr('clip-path', 'url(#rect-clip)')
      .call(this.xAxis);
    svg.append('g').attr('class', 'y-axis');
    svg.append('g').attr('class', 'y-gridline');
    this.bars = svg
      .selectAll('g.bars')
      .data(seriesDatas)
      .join('g')
      .attr('class', 'bars')
      .attr('fill', (d, i) => this.getColor(i))
      .selectAll('g')
      .data((d) => d)
      .join('g')
      .append('rect')
      .attr('x', (d, i) => {
        return this.x(d.key);
      })
      .attr('y', height - margin.bottom)
      .attr('width', bandWidth)
      .attr('height', 0)
      .attr('clip-path', 'url(#rect-clip)');
    svg.selectAll('g.bars g').append('title').text((d, i, bar) => {
      return this.getFormattedValue(d3.sum([d[1], -d[0]]));
    });
    this.line = svg.append('path')
      .datum(seriesDatas[0])
      .attr('transform', `translate(${bandWidth / 2},0)`)
      .attr('fill', 'none')
      .attr('stroke', this.getColor(n))
      .attr('stroke-width', 1.5)
      .attr('stroke-linecap', 'round')
      .attr('stroke-linejoin', 'round')
      .attr('d', curve);

    const extent = [[margin.left, margin.top], [width - margin.right, height - margin.bottom]];

    svg.call(d3.zoom()
        .scaleExtent([1, 8])
        .translateExtent(extent)
        .extent(extent)
        .on('zoom', (event) => {
          const numOfSeries = this.getNumOfSeries();
          const bandWidth = this.getBandWidth();

          this.x.rangeRound(this.getXSizeRange().map(d => event.transform.applyX(d)));
          if ((this.options as BarChartOptions).layout === 'stacked') {
            this.bars.attr('x', d => this.x(d.key))
              .attr('width', bandWidth);
          } else {
            this.bars
            .attr('x', (d) => {
              return this.x(d.key) + (bandWidth / numOfSeries) * d[d.length - 1];
            })
            .attr('width', bandWidth / numOfSeries)
          }
          this.svg.selectAll('.x-axis').call(this.xAxis);
          this.line.attr('d', curve);
        }));

    this.renderer.appendChild(this.elementRef.nativeElement, svg.node());
    this.update();
  }

  clear(): void {
    if (this.svg) {
      this.svg.selectAll('*').remove();
    }
  }

  whenViewportResize(): void {

  }

  private getNumOfSeries(): number {
    return this.data && this.data[0] ? (this.data[0] as Array<number>).length - 1 : 0;
  }

  private getBandWidth(): number {
    if (typeof this.x.bandwidth === 'function') {
      return this.x.bandwidth();
    }
    const range = this.getXSizeRange();

    return (range[1] - range[0]) / (this.data ? this.data.length : 1);
  }
}
