import { Component, EventEmitter, OnInit, Output } from '@angular/core';

import { CommunicationService } from 'app/shared/services/communication.service';



@Component({
  selector: 'app-operation-toolbar',
  templateUrl: './operation-toolbar.component.html',
  styleUrls: ['./operation-toolbar.component.scss']
})
export class OperationToolbarComponent implements OnInit {
  @Output() new = new EventEmitter();
  @Output() save = new EventEmitter();
  @Output() delete = new EventEmitter();
  @Output() search = new EventEmitter();
  @Output() info = new EventEmitter();
  @Output() duplicate = new EventEmitter();
  @Output() print = new EventEmitter();
  @Output() configure = new EventEmitter();
  @Output() expand = new EventEmitter();
  @Output() refresh = new EventEmitter();
  @Output() help = new EventEmitter();

  constructor(private communication: CommunicationService) { }

  ngOnInit(): void {
  }

  onClick(event: MouseEvent, button: string): void {
    event.stopPropagation();
    switch (button) {
      case 'new':
        this.new.emit();
        break;
      case 'save':
        this.save.emit();
        break;
      case 'delete':
        this.delete.emit();
        break;
      case 'search':
        this.search.emit();
        break;
      case 'info':
        this.info.emit();
        break;
      case 'duplicate':
        this.duplicate.emit();
        break;
      case 'print':
        this.print.emit();
        break;
      case 'configure':
        this.configure.emit();
        break;
      case 'expand':
        this.communication.giveFullScreenCommand();
        this.expand.emit();
        break;
      case 'refresh':
        this.communication.giveRefreshCommand();
        this.refresh.emit();
        break;
      case 'help':
        this.refresh.emit();
        break;
      default:
    }
  }

}
