import { Injectable } from '@angular/core';
import { fromEvent, Observable } from 'rxjs';
import { debounceTime, map } from 'rxjs/operators';

import { IViewportChange } from './viewport-change';



@Injectable()
export class EventService {
  private oldWindowDimension = {
    width: 0,
    height: 0
  };
  private viewportDimensionChange: Observable<IViewportChange>;

  constructor() {
    this.init();
  }

  onViewportDimensionChange(): Observable<IViewportChange> {
    return this.viewportDimensionChange;
  }

  resetWindowDimension(): void {
    const oldDimension = this.oldWindowDimension;

    oldDimension.width = window.innerWidth;
    oldDimension.height = window.innerHeight;
  }

  private init(): void {
    this.viewportDimensionChange = fromEvent(window, 'resize').pipe(
      debounceTime(300),
      map(() => {
        const newWidth = window.innerWidth;
        const newHeight = window.innerHeight;
        const oldWidth = this.oldWindowDimension.width;
        const oldHeight = this.oldWindowDimension.height;
        const widthChanged = newWidth !== oldWidth;
        const heightChanged = newHeight !== oldHeight;
        const changeEvent: IViewportChange = {
          width: widthChanged,
          height: heightChanged,
          both: widthChanged && heightChanged,
          either: widthChanged || heightChanged
        }

        this.resetWindowDimension();
        return changeEvent;
      })
    );
  }
}
