import { IChartValue } from "./chart-data";

export type BAR_LAYOUT_TYPE = 'grouped' | 'stacked';

export const PRIMARY_COLORS: Array<string> = /*[
  // '#e1f4fa',
  '#b2e2f3',
  '#82cfec',
  '#55bee4',
  '#37b0e0',
  '#1da2db',
  '#1894cd',
  '#0f81ba',
  '#0e71a7',
  '#055285'
];*/
[
  '#a6aaad',
  '#11a3dc',
  '#5e92a8',
  '#10536d',
  '#012345'
]

export interface ISeriesBase {
  name?: string;
  color?: string;
  type?: string;
}

export interface IChartOptionsBase {
  width?: number | string;
  height?: number | string;
  margin?: {
    top?: number;
    right?: number;
    bottom?: number;
    left?: number;
  };
  delay?: number;
  series?: Array<ISeriesBase>;
  valueFormat?: (value: IChartValue) => string;
  xAxisValueFormat?: (value: IChartValue) => string;
  yAxisValueFormat?: (value: IChartValue) => string;
}

export class BarChartOptions implements IChartOptionsBase {
  width: string | number = '100%';
  height: string | number = '100%';
  margin = {
    top: 10,
    right: 0,
    bottom: 30,
    left: 80
  };
  layout: BAR_LAYOUT_TYPE = 'grouped';
  delay: number = 20;
  series: Array<ISeriesBase> = PRIMARY_COLORS.map((color) => {
    return {
      color: color
    }
  });
  valueFormat?: (value: IChartValue) => string;
  xAxisValueFormat?: (value: IChartValue) => string;
  yAxisValueFormat?: (value: IChartValue) => string;
}

export class SunburstChartOptions implements IChartOptionsBase {
  width: string | number = '100%';
  height: string | number = '100%';
  margin = {
    top: 0,
    right: 0,
    bottom: 0,
    left: 0
  };
  delay: number = 20;
  series: Array<ISeriesBase> = PRIMARY_COLORS.map((color) => {
    return {
      color: color
    }
  });
  valueFormat?: (value: IChartValue) => string;
}
