import { Injectable, InjectionToken } from '@angular/core';
import { Observable, of } from 'rxjs';
import { delay, tap } from 'rxjs/operators';

import { IUserProfile, User } from './user';

export interface IAuthService {
  isLoggedIn: boolean;
  // store the URL so we can redirect after logging in
  redirectUrl: string;
  user: IUserProfile;
  login: (account: string, password: string) => Observable<boolean>;
  logout: () => Observable<boolean>;
  checkSignInStatus: () => Observable<boolean>;
  getToken: () => string;
}

export const AUTH_SERVICE_TOKEN = new InjectionToken<AuthService>('Manually constructed AuthService', {
  providedIn: 'root',
  factory: () => new AuthService(),
});

@Injectable()
export class AuthService implements IAuthService {
  isLoggedIn = false;
  redirectUrl: string = '/admin';
  user = new User();
  
  private token: string;

  constructor() {
  }

  login(account: string, password: string): Observable<boolean> {
    return of(true).pipe(
      delay(1000),
      tap(val => this.isLoggedIn = true)
    );
  }

  logout(): Observable<boolean> {
    return of(true).pipe(
      delay(1000),
      tap(val => this.isLoggedIn = false)
    );
  }

  checkSignInStatus(): Observable<boolean> {
    return of(true).pipe(
      delay(1000),
      tap(val => this.isLoggedIn = false)
    );
  }

  getToken(): string {
    return this.token;
  }

  protected setToken(value: string): void {
    this.token = value;
  }
}
