import { Component, Inject, OnInit } from '@angular/core';
import { Router } from '@angular/router';

import { IUserProfile } from 'app/authorization/user';
import { AUTH_SERVICE_TOKEN, IAuthService } from 'app/authorization/auth.service';



@Component({
  selector: 'app-management-header',
  templateUrl: './management-header.component.html',
  styleUrls: ['./management-header.component.scss']
})
export class ManagementHeaderComponent implements OnInit {
  signed = false;
  user: IUserProfile;

  constructor(
    private router: Router,
    @Inject(AUTH_SERVICE_TOKEN) private authService: IAuthService
  ) {
    this.user = this.authService.user;
  }

  ngOnInit(): void {
    this.signed = this.authService.isLoggedIn;
  }

  logout(): void {
    this.authService.logout().subscribe((result) => {
      if (result) {
        this.router.navigate(['/sign-in']);
      }
    });
  }
}
