import { AfterViewInit, Component, ElementRef, Input, OnDestroy } from '@angular/core';
import { Subscription } from 'rxjs';
import * as d3 from 'd3';

import { IChartOptionsBase, ISeriesBase } from './chart-options';
import { ISunburstData, IChartValue } from './chart-data';
import { EventService } from '../services/event.service';

type ChartSerieData = Array<Array<IChartValue> | ISunburstData>;

@Component({
  template: '',
})
export abstract class ChartBase implements AfterViewInit, OnDestroy {
  @Input() set options(value: IChartOptionsBase) {
    const oldSeries = this.options.series;

    if (value.series && oldSeries) {
      value.series.forEach((item, index) => {
        if (oldSeries[index]) {
          oldSeries[index] = {
            ...oldSeries[index],
            ...item
          };
        } else {
          oldSeries[index] = item;
        }
      });
    }
    this._options = {
      ...this._options,
      ...value,
      series: oldSeries
    };
    this.resetDimension();
    this.clear();
    this.draw();
  }
  get options(): IChartOptionsBase {
    return this._options;
  }

  @Input() set data(value: ChartSerieData) {
    this._data = value;
    this.clear();
    this.draw();
  }
  get data(): ChartSerieData {
    return this._data;
  }

  width: number;
  height: number;

  protected _options: IChartOptionsBase;
  protected _data: ChartSerieData;
  protected color: (value: string | number) => string = d3.scaleSequential(d3.interpolateBlues);
  protected subscription: Subscription;

  constructor(
    protected elementRef: ElementRef<HTMLElement>,
    protected eventService: EventService
  ) {}

  ngAfterViewInit(): void {
    this.listenViewportResize();
  }

  ngOnDestroy(): void {
    this.subscription.unsubscribe();
  }

  resetDimension(): void {
    const parentEl = this.elementRef.nativeElement.parentElement;

    this.width = this.coerceNumber(this.options.width, parentEl.offsetWidth);
    this.height = this.coerceNumber(
      this.options.height,
      parentEl.offsetHeight,
    );
  }

  abstract draw(): void;
  abstract clear(): void;
  abstract whenViewportResize(): void;

  protected coerceNumber(
    value: number | string,
    dependedValue: number,
  ): number {
    if (typeof value === 'undefined') {
      return dependedValue;
    }
    if (typeof value === 'string') {
      if (value.endsWith('%')) {
        return (dependedValue * parseInt(value)) / 100;
      } else {
        return parseInt(value);
      }
    }

    return value as number;
  }

  protected getColor(index: number): string {
    const series = this.options.series;

    if (series && series[index]) {
      return series[index].color;
    } else {
      this.color(index);
    }

    return '#000'
  }

  protected getFormattedValue(value: IChartValue): string {
    if (typeof this.options.valueFormat === 'function') {
      return this.options.valueFormat(value);
    }
    return this.getDisplayValue(value);
  }

  protected getFormattedXValue(value: IChartValue): string {
    if (typeof this.options.xAxisValueFormat === 'function') {
      return this.options.xAxisValueFormat(value);
    }
    return this.getDisplayValue(value);
  }

  protected getFormattedYValue(value: IChartValue): string {
    if (typeof this.options.yAxisValueFormat === 'function') {
      return this.options.yAxisValueFormat(value);
    }
    return this.getDisplayValue(value);
  }

  protected getDisplayValue(value: IChartValue): string {
    return typeof value !== 'undefined' ? value.toString() : '';
  }

  protected listenViewportResize() {
    this.subscription.add(
      this.eventService.onViewportDimensionChange().subscribe((event) => {
        this.resetDimension();
        this.whenViewportResize();
        this.clear();
        this.draw();
      })
    );
  }

  protected getXSizeRange(): [number, number] {
    const width = this.width;
    const margin = this.options.margin;

    return [margin.left, width - margin.right];
  }

  protected getYSizeRange(): [number, number] {
    const height = this.height;
    const margin = this.options.margin;

    return [height - margin.bottom, margin.top];
  }
}
